module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [1:0] cnt;
reg [9:0] data_out_reg;
reg valid_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        cnt <= 0;
        data_out_reg <= 0;
        valid_out_reg <= 0;
    end else begin

        case ({valid_in, cnt})
            2'b00: begin

                cnt <= 0;
                data_out_reg <= 0;
                valid_out_reg <= 0;
            end
            2'b01: begin

                cnt <= cnt + 1;
                data_out_reg <= 0;
                valid_out_reg <= 0;
            end
            2'b10: begin

                cnt <= cnt + 1;
                data_out_reg <= data_in;
                valid_out_reg <= 0;
            end
            2'b11: begin

                cnt <= cnt + 1;
                data_out_reg <= data_in + data_out_reg;
                valid_out_reg <= 0;
            end
            2'b10: begin

                cnt <= cnt + 1;
                data_out_reg <= data_in + data_out_reg;
                valid_out_reg <= 0;
            end
            2'b11: begin

                cnt <= cnt + 1;
                data_out_reg <= data_in + data_out_reg;
                valid_out_reg <= 1;
            end
            default: begin

                cnt <= 0;
                data_out_reg <= 0;
                valid_out_reg <= 0;
            end
        endcase
    end
end

assign valid_out = valid_out_reg;
assign data_out = data_out_reg;
endmodule
